UPDATE wiki_ingest_tasks
SET source_id=#{sourceId}, file_name=#{fileName}, status=#{status}, progress=#{progress},
    step=#{step}, total_chunks=#{totalChunks}, completed_chunks=#{completedChunks},
    pages_created=#{pagesCreated}, pages_updated=#{pagesUpdated}, error_message=#{errorMessage},
    quality_report=#{qualityReport}, operator_id=#{operatorId}
WHERE id=#{id}

UPDATE wiki_ingest_tasks
SET status=#{status}, error_message=#{errorMessage}
WHERE id=#{id}

UPDATE wiki_ingest_tasks
SET quality_report=#{qualityReport}
WHERE id=#{id}

UPDATE wiki_ingest_tasks
SET section_facts=#{sectionFacts}
WHERE id=#{id}

UPDATE wiki_ingest_tasks
SET page_plan=#{pagePlan}
WHERE id=#{id}
